import{_ as e,o as s,c as i,ae as l}from"./chunks/framework.C7FLYIpo.js";const u=JSON.parse('{"title":"게이트웨이 라이프사이클","description":"macOS에서 게이트웨이 라이프사이클 (launchd)","frontmatter":{"title":"게이트웨이 라이프사이클","description":"macOS에서 게이트웨이 라이프사이클 (launchd)"},"headers":[],"relativePath":"platforms/mac/child-process.md","filePath":"platforms/mac/child-process.md","lastUpdated":null}'),t={name:"platforms/mac/child-process.md"};function n(c,a,o,h,d,p){return s(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="macos에서-게이트웨이-라이프사이클" tabindex="-1">macOS에서 게이트웨이 라이프사이클 <a class="header-anchor" href="#macos에서-게이트웨이-라이프사이클" aria-label="Permalink to &quot;macOS에서 게이트웨이 라이프사이클&quot;">​</a></h1><p>macOS 앱은 기본적으로 <strong>launchd를 통해 게이트웨이를 관리</strong>하며 게이트웨이를 자식 프로세스로 생성하지 않습니다. 먼저 구성된 포트에서 이미 실행 중인 게이트웨이에 연결을 시도합니다. 도달할 수 없으면 외부 <code>openclaw</code> CLI를 통해 launchd 서비스를 활성화합니다 (임베딩된 런타임 없음). 이를 통해 로그인 시 안정적인 자동 시작과 충돌 시 재시작이 가능합니다.</p><p>자식 프로세스 모드 (앱이 직접 게이트웨이를 생성)는 현재 <strong>사용되지 않습니다</strong>. UI와 더 긴밀한 결합이 필요하다면 터미널에서 게이트웨이를 수동으로 실행하십시오.</p><h2 id="기본-동작-launchd" tabindex="-1">기본 동작 (launchd) <a class="header-anchor" href="#기본-동작-launchd" aria-label="Permalink to &quot;기본 동작 (launchd)&quot;">​</a></h2><ul><li>앱은 <code>ai.openclaw.gateway</code>로 레이블된 사용자별 LaunchAgent를 설치합니다 (<code>--profile</code>/<code>OPENCLAW_PROFILE</code> 사용 시 <code>ai.openclaw.&amp;lt;profile&amp;gt;</code>; 레거시 <code>com.openclaw.*</code> 지원됨).</li><li>로컬 모드가 활성화되면 앱은 LaunchAgent가 로드되어 있고 필요한 경우 게이트웨이를 시작하도록 합니다.</li><li>로그는 launchd 게이트웨이 로그 경로에 기록됩니다 (Debug Settings에서 볼 수 있음).</li></ul><p>공통 명령:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kickstart</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gui/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$UID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ai.openclaw.gateway</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gui/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$UID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ai.openclaw.gateway</span></span></code></pre></div><p>명명된 프로필 실행 시 레이블을 <code>ai.openclaw.&amp;lt;profile&amp;gt;</code>로 교체하십시오.</p><h2 id="서명되지-않은-개발-빌드" tabindex="-1">서명되지 않은 개발 빌드 <a class="header-anchor" href="#서명되지-않은-개발-빌드" aria-label="Permalink to &quot;서명되지 않은 개발 빌드&quot;">​</a></h2><p><code>scripts/restart-mac.sh --no-sign</code>은 서명 키가 없는 빠른 로컬 빌드용입니다. launchd가 서명되지 않은 릴레이 바이너리를 가리키지 않도록 다음을 수행합니다:</p><ul><li><code>~/.openclaw/disable-launchagent</code>를 씁니다.</li></ul><p><code>scripts/restart-mac.sh</code>의 서명된 실행은 마커가 있으면 이 재정의를 지웁니다. 수동으로 재설정하려면:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/disable-launchagent</span></span></code></pre></div><h2 id="연결-전용-모드" tabindex="-1">연결 전용 모드 <a class="header-anchor" href="#연결-전용-모드" aria-label="Permalink to &quot;연결 전용 모드&quot;">​</a></h2><p>macOS 앱이 launchd를 <strong>절대 설치하거나 관리하지 않도록</strong> 강제하려면 <code>--attach-only</code> (또는 <code>--no-launchd</code>)로 시작하십시오. 이렇게 하면 <code>~/.openclaw/disable-launchagent</code>가 설정되므로 앱은 이미 실행 중인 게이트웨이에만 연결합니다. Debug Settings에서 동일한 동작을 전환할 수 있습니다.</p><h2 id="원격-모드" tabindex="-1">원격 모드 <a class="header-anchor" href="#원격-모드" aria-label="Permalink to &quot;원격 모드&quot;">​</a></h2><p>원격 모드는 로컬 게이트웨이를 시작하지 않습니다. 앱은 원격 호스트에 SSH 터널을 사용하고 해당 터널을 통해 연결합니다.</p><h2 id="launchd를-선호하는-이유" tabindex="-1">launchd를 선호하는 이유 <a class="header-anchor" href="#launchd를-선호하는-이유" aria-label="Permalink to &quot;launchd를 선호하는 이유&quot;">​</a></h2><ul><li>로그인 시 자동 시작.</li><li>내장된 재시작/KeepAlive 의미론.</li><li>예측 가능한 로그 및 감독.</li></ul><p>진정한 자식 프로세스 모드가 다시 필요한 경우 별도의 명시적 개발 전용 모드로 문서화해야 합니다.</p>`,20)])])}const k=e(t,[["render",n]]);export{u as __pageData,k as default};
